/**
 * Compile-time constants injected by Vite's `define` (see
 * vite.config.ts). The values are written verbatim into the bundle
 * at build time, so source code can compare them against the
 * server-served version.json without making any extra round trip
 * for "what version am I running".
 */
declare const __BUILD_VERSION__: string
declare const __BUILT_AT__: string
